    todos = list(_todos.values())

    # Apply optional filter
    completed_param = request.query_params.get("completed")
    if completed_param:
        is_completed = completed_param.lower() in ["true", "1", "yes"]
        todos = [t for t in todos if t.completed == is_completed]

    # Serialize Todo objects
    result = [
        {
            "id": t.id,
            "title": t.title,
            "completed": t.completed,
            "created_at": t.created_at.isoformat()
        }
        for t in todos
    ]
    return Response.json(result)

def create_todo(request: Request) -> Response:
    """
    POST /todos
    Creates a new todo.
    Expected JSON body: { "title": "string", "completed": boolean }
    """
    data = request.json
    title = data.get("title")

    if not title:
        return Response.bad_request("Field 'title' is required")

    global _next_id
    new_id = _next_id
    completed = data.get("completed", False)

    todo = Todo(id=new_id, title=title, completed=completed)
    _todos[new_id] = todo
    _next_id += 1

    result = {
        "id": todo.id,
        "title": todo.title,
        "completed": todo.completed,
        "created_at": todo.created_at.isoformat()
    }
    return Response.json(result, status_code=201)

def update_todo(request: Request, id: str) -> Response:
    """
    PUT /todos/{id}
    Updates an existing todo.
    Expected JSON body: { "title": "string", "completed": boolean } (fields optional)
    """
    try:
        todo_id = int(id)
    except ValueError:
        return Response.bad_request("Invalid ID format")

    if todo_id not in _todos:
        return Response.not_found(f"Todo with id {id} not found")

    todo = _todos[todo_id]
    data = request.json

    if "title" in data:
        todo.title = data["title"]
    if "completed" in data:
        todo.completed = bool(data["completed"])

    result = {
        "id": todo.id,
        "title": todo.title,
        "completed": todo.completed,
        "created_at": todo.created_at.isoformat()
    }
    return Response.json(result)

def delete_todo(request: Request, id: str) -> Response:
    """
    DELETE /todos/{id}
    Deletes an existing todo.
    """
    try:
        todo_id = int(id)
    except ValueError:
        return Response.bad_request("Invalid ID format")

    if todo_id not in _todos:
        return Response.not_found(f"Todo with id {id} not found")

    del _todos[todo_id]
    return Response.no_content()


